trigger.keyword.code_template:
@filter.event_message_type(filter.EventMessageType.ALL)
async def {{handler_name}}(self, event: AstrMessageEvent):
    '''关键词触发处理器'''
    msg = event.message_str{% if not params.case_sensitive %}.lower(){% endif %}
    keywords = {{params.keywords}}
    matched = None
    {% if params.match_all %}
    if all(kw in msg for kw in keywords):
        matched = keywords
    {% else %}
    for kw in keywords:
        if kw in msg:
            matched = kw
            break
    {% endif %}
    if matched:
        {{handler_body}}

