util.data_store.code_template:
import json
from pathlib import Path
_data_file = Path(__file__).parent / "{{params.file_name}}"
{% if params.operation == 'save' %}
if not _data_file.exists():
    _data_store = {}
else:
    with open(_data_file, 'r', encoding='utf-8') as _f:
        _data_store = json.load(_f)
_data_store[{{params.key | render_template}}] = {{params.value | render_template}}
with open(_data_file, 'w', encoding='utf-8') as _f:
    json.dump(_data_store, _f, ensure_ascii=False, indent=2)
{% elif params.operation == 'load' %}
if _data_file.exists():
    with open(_data_file, 'r', encoding='utf-8') as _f:
        _data_store = json.load(_f)
    {{params.save_to or '_loaded_data'}} = _data_store.get({{params.key | render_template}})
else:
    {{params.save_to or '_loaded_data'}} = None
{% elif params.operation == 'delete' %}
if _data_file.exists():
    with open(_data_file, 'r', encoding='utf-8') as _f:
        _data_store = json.load(_f)
    if {{params.key | render_template}} in _data_store:
        del _data_store[{{params.key | render_template}}]
        with open(_data_file, 'w', encoding='utf-8') as _f:
            json.dump(_data_store, _f, ensure_ascii=False, indent=2)
{% elif params.operation == 'exists' %}
_exists_result = False
if _data_file.exists():
    with open(_data_file, 'r', encoding='utf-8') as _f:
        _data_store = json.load(_f)
    _exists_result = {{params.key | render_template}} in _data_store
{% endif %}

