trigger.file_received.code_template:
@filter.event_message_type(filter.EventMessageType.ALL)
async def {{handler_name}}(self, event: AstrMessageEvent):
    '''文件接收触发'''
    _has_file = any(isinstance(c, Comp.File) for c in event.get_messages())
    if not _has_file:
        return
    _file_comp = next((c for c in event.get_messages() if isinstance(c, Comp.File)), None)
    if _file_comp:
        file_name = _file_comp.name if hasattr(_file_comp, 'name') else ""
        file_url = _file_comp.url if hasattr(_file_comp, 'url') else ""
        file_size = _file_comp.size if hasattr(_file_comp, 'size') else 0
        {% if params.file_types %}
        _allowed = any(file_name.endswith(ft) for ft in {{params.file_types}})
        if not _allowed:
            return
        {% endif %}
        {% if params.max_size > 0 %}
        if file_size > {{params.max_size}} * 1024:
            return
        {% endif %}
        {{handler_body}}
